const mongoose = require("mongoose");
const jwt = require("jsonwebtoken");
const JWT_SECRET = process.env.ACCESS_TOKEN_SECRET;

// Connect to the Hospital database
mongoose.connect("mongodb://localhost:27017/hospitalDB", {
    useNewUrlParser: true,
    useUnifiedTopology: true
});

// Connect to the Patient database
const patientDB = mongoose.createConnection("mongodb://localhost:27017/patientDB", {
    useNewUrlParser: true,
    useUnifiedTopology: true
});

// Connect to the Admin database
const adminDB = mongoose.createConnection("mongodb://localhost:27017/adminDB", {
    useNewUrlParser: true,
    useUnifiedTopology: true
});

// Define Patient schema
const patientSchema = new mongoose.Schema({
    name: String,
    email: String,
    password: String
});

// Define Admin schema
const adminSchema = new mongoose.Schema({
    username: String,
    email: String,
    password: String
});

// Create models in the Hospital database
const Patient = mongoose.model("Patient", patientSchema, "patients");
const Admin = mongoose.model("Admin", adminSchema, "admins");

// Create models for separate databases
const PatientDBModel = patientDB.model("Patient", patientSchema);
const AdminDBModel = adminDB.model("Admin", adminSchema);

// Login function with JWT authentication
async function loginUser(email, password, role) {
    let user;

    if (role === "patient") {
        user = await Patient.findOne({ email, password });
    } else if (role === "admin") {
        user = await Admin.findOne({ email, password });
    }

    if (user) {
        const token = jwt.sign(
            { id: user._id, email: user.email, role },
            JWT_SECRET,
            { expiresIn: "30m" }
        );
        console.log(`Login successful as ${role}`);
        return { user, token };
    } else {
        console.log("Invalid credentials");
        return null;
    }
}

exports.verifyToken = (req, res, next) => {
    const authHeader = req.headers["authorization"];
    const token = authHeader && authHeader.split(" ")[1];

    if (!token) {
        return res.status(401).json({ message: "Access Denied! No token provided." });
    }

    jwt.verify(token, JWT_SECRET, (err, decoded) => {
        if (err) {
            return res.status(403).json({ message: "Invalid or expired token!" });
        }

        req.user = decoded; // Contains user data from token
        next();
    });
};

exports.generateToken = (user) => {
    return jwt.sign(
        { id: user._id, email: user.email, role: user.role }, // Store essential user data
        JWT_SECRET,
        { expiresIn: "30m" }
    );
};

module.exports = { Patient, Admin, PatientDBModel, AdminDBModel, loginUser };
